import React, { useState, useEffect, useRef } from 'react';

const bgImages = [
  'https://images.unsplash.com/photo-1500382017468-9049fed747ef?w=1600&q=80',
  'https://images.unsplash.com/photo-1464226184884-fa280b87c399?w=1600&q=80',
  'https://images.unsplash.com/photo-1523741543316-beb7fc7023d8?w=1600&q=80',
];

const produceSlides = [
  { url: 'https://images.unsplash.com/photo-1540148426945-6cf22a6b2383?w=500&q=80', label: 'Fresh Tomatoes', tag: 'Vegetable' },
  { url: 'https://images.unsplash.com/photo-1574316071802-0d684efa7bf5?w=500&q=80', label: 'Sweet Mangoes', tag: 'Fruit' },
  { url: 'https://images.unsplash.com/photo-1550828520-4cb496926fc9?w=500&q=80', label: 'Red Apples', tag: 'Fruit' },
  { url: 'https://images.unsplash.com/photo-1518977676601-b53f82aba655?w=500&q=80', label: 'Potatoes', tag: 'Vegetable' },
  { url: 'https://images.unsplash.com/photo-1587334207104-8c7583d7e83e?w=500&q=80', label: 'Fresh Grapes', tag: 'Fruit' },
  { url: 'https://images.unsplash.com/photo-1598170845058-32b9d6a5da37?w=500&q=80', label: 'Carrots', tag: 'Vegetable' },
  { url: 'https://images.unsplash.com/photo-1589927986089-35812388d1f4?w=500&q=80', label: 'Bananas', tag: 'Fruit' },
  { url: 'https://images.unsplash.com/photo-1611735341450-74d61e660ad2?w=500&q=80', label: 'Broccoli', tag: 'Vegetable' },
];

// const stats = [
//   { value: '12,000+', label: 'Farmers' },
//   { value: '₹4.2Cr', label: 'Traded Daily' },
//   { value: '28', label: 'States Covered' },
//   { value: '99%', label: 'Satisfaction' },
// ];

function Login({ onLogin }) {
  const [view, setView] = useState('landing');
  const [role, setRole] = useState('buyer');
  const [animating, setAnimating] = useState(false);
  const [slideDir, setSlideDir] = useState('right');

  const [bgIndex, setBgIndex] = useState(0);
  const [bgFade, setBgFade] = useState(true);
  const [produceIndex, setProduceIndex] = useState(0);

  // Login
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Buyer
  const [buyerName, setBuyerName] = useState('');
  const [buyerLocation, setBuyerLocation] = useState('');
  const [buyerInterest, setBuyerInterest] = useState('');

  // Seller
  const [sellerName, setSellerName] = useState('');
  const [sellerLocation, setSellerLocation] = useState('');
  const [sellerAadhar, setSellerAadhar] = useState('');
  const [sellerPan, setSellerPan] = useState('');
  const [sellerFile, setSellerFile] = useState(null);
  const [sellerFileName, setSellerFileName] = useState('');
  const fileInputRef = useRef(null);

  const [signupError, setSignupError] = useState('');

  useEffect(() => {
    const interval = setInterval(() => {
      setBgFade(false);
      setTimeout(() => { setBgIndex(i => (i + 1) % bgImages.length); setBgFade(true); }, 600);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setProduceIndex(i => (i + 1) % produceSlides.length);
    }, 2200);
    return () => clearInterval(interval);
  }, []);

  const navigate = (nextView, dir = 'left') => {
    if (animating) return;
    setLoginError(''); setSignupError('');
    setAnimating(true); setSlideDir(dir);
    setTimeout(() => { setView(nextView); setAnimating(false); }, 400);
  };

  const handleLogin = () => {
    if (!loginEmail.trim() || !loginPassword.trim()) {
      setLoginError('⚠️ Please fill in both email and password.');
      return;
    }
    onLogin({ role: 'user' });
  };

  const handleSignup = () => {
    if (role === 'buyer') {
      if (!buyerName.trim() || !buyerLocation.trim()) {
        setSignupError('⚠️ Please fill in your name and location.');
        return;
      }
    } else {
      if (!sellerName.trim() || !sellerLocation.trim() || !sellerAadhar.trim() || !sellerPan.trim()) {
        setSignupError('⚠️ Please fill in all required fields.');
        return;
      }
      if (!sellerFile) {
        setSignupError('⚠️ Please upload your income proof.');
        return;
      }
    }
    onLogin({ role });
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setSellerFile(file);
      setSellerFileName(file.name);
      setSignupError('');
    }
  };

  const trackTranslate = role === 'buyer' ? '0%' : '-50%';

  // Visible produce cards: 3 at a time, wrapping
  const getVisible = () => {
    const result = [];
    for (let i = 0; i < 3; i++) {
      result.push(produceSlides[(produceIndex + i) % produceSlides.length]);
    }
    return result;
  };

  return (
    <div className="portal-root">
      <div className={`real-bg ${bgFade ? 'bg-visible' : 'bg-hidden'}`}
        style={{ backgroundImage: `url(${bgImages[bgIndex]})` }} />
      <div className="bg-overlay" />

      {/* NAVBAR */}
      <nav className="top-nav">
        <div className="nav-brand">
          <span className="brand-leaf">🌿</span>
          <span className="brand-text">AGRI<span className="brand-accent">-AI</span></span>
        </div>
        <div className="nav-links">
          <span>Home</span>
          <span>About Us</span>
          <span>Communities</span>
          <span>Contacts</span>
          <span className="nav-help">Help</span>
        </div>
      </nav>

      {/* MAIN LAYOUT */}
      <div className="main-layout">

        {/* LEFT INFO PANEL */}
        <div className="info-side">
          <div className="info-badge">🌱 India's #1 Agri Marketplace</div>

          <h2 className="info-title">
            Farm Fresh,<br />
            <span className="info-title-accent">Direct to You</span>
          </h2>
          <p className="info-desc">
            Bridging the gap between farmers and buyers across India.
            No middlemen, fair pricing, and real-time market access —
            straight from the soil to your doorstep.
          </p>

          {/* Stats Row */}
          <div className="stats-row">
            {stats.map((s, i) => (
              <div className="stat-card" key={i}>
                <span className="stat-value">{s.value}</span>
                <span className="stat-label">{s.label}</span>
              </div>
            ))}
          </div>

          {/* Auto Produce Slider — no manual controls */}
          <div className="produce-slider-wrap">
            <p className="slider-heading">
              <span className="heading-dot"></span>
              Live Market — Today's Produce
            </p>
            <div className="produce-track">
              {getVisible().map((item, idx) => (
                <div className="produce-card" key={`${produceIndex}-${idx}`}>
                  <img src={item.url} alt={item.label} className="produce-img" />
                  <div className="produce-info">
                    <span className="produce-tag">{item.tag}</span>
                    <span className="produce-label">{item.label}</span>
                  </div>
                </div>
              ))}
            </div>
            {/* Progress dots — view only */}
            <div className="slider-dots">
              {produceSlides.map((_, i) => (
                <span key={i} className={`dot ${i === produceIndex ? 'dot-active' : ''}`} />
              ))}
            </div>
          </div>
        </div>

        {/* RIGHT AUTH CARD */}
        <div className="auth-side">
          <div className="glass-card">
            <div className={`slide-container ${animating ? `exit-${slideDir}` : 'enter'}`} key={view}>

              {/* LANDING */}
              {view === 'landing' && (
                <div className="view-panel">
                  <div className="portal-icon">
                    <div className="icon-ring"><span>🌾</span></div>
                  </div>
                  <h1 className="portal-title">Online Farm<br />Portal</h1>
                  <p className="portal-sub">Connect. Trade. Grow.</p>
                  <div className="landing-btns">
                    <button className="btn-agri" onClick={() => navigate('login', 'left')}>
                      <span className="btn-icon">🔑</span> Login
                    </button>
                    <button className="btn-agri btn-secondary" onClick={() => navigate('signup', 'left')}>
                      <span className="btn-icon">🌱</span> Sign Up
                    </button>
                  </div>
                </div>
              )}

              {/* LOGIN */}
              {view === 'login' && (
                <div className="view-panel">
                  <div className="portal-icon small">
                    <div className="icon-ring"><span>🔒</span></div>
                  </div>
                  <h2 className="panel-title">Secure Login</h2>
                  <p className="panel-sub">Welcome back, farmer</p>
                  <div className="input-group">
                    <span className="input-icon">👤</span>
                    <input type="text"
                      className={`agri-input ${loginError && !loginEmail.trim() ? 'input-error' : ''}`}
                      placeholder="Email / Mobile *"
                      value={loginEmail}
                      onChange={e => { setLoginEmail(e.target.value); setLoginError(''); }} />
                  </div>
                  <div className="input-group">
                    <span className="input-icon">🔐</span>
                    <input type="password"
                      className={`agri-input ${loginError && !loginPassword.trim() ? 'input-error' : ''}`}
                      placeholder="Password *"
                      value={loginPassword}
                      onChange={e => { setLoginPassword(e.target.value); setLoginError(''); }} />
                  </div>
                  {loginError && <p className="error-msg">{loginError}</p>}
                  <a className="forgot-link">Forgot Password?</a>
                  <button className="btn-agri full-w mt-20" onClick={handleLogin}>Access Dashboard →</button>
                  <button className="btn-back" onClick={() => navigate('landing', 'right')}>← Back</button>
                </div>
              )}

              {/* SIGNUP */}
              {view === 'signup' && (
                <div className="view-panel">
                  <h2 className="panel-title">Join the Network</h2>

                  <div className="role-toggle-wrap">
                    <div className="role-slider" style={{ left: role === 'buyer' ? '4px' : 'calc(50%)' }}></div>
                    <button className={`role-btn ${role === 'buyer' ? 'active' : ''}`} onClick={() => { setSignupError(''); setRole('buyer'); }}>🛒 Buyer</button>
                    <button className={`role-btn ${role === 'seller' ? 'active' : ''}`} onClick={() => { setSignupError(''); setRole('seller'); }}>🚜 Seller</button>
                  </div>

                  <div className="role-forms-viewport">
                    <div className="role-forms-track" style={{ transform: `translateX(${trackTranslate})` }}>

                      {/* BUYER FORM */}
                      <div className="role-form-panel">
                        <div className="input-group">
                          <span className="input-icon">👤</span>
                          <input type="text"
                            className={`agri-input ${signupError && role === 'buyer' && !buyerName.trim() ? 'input-error' : ''}`}
                            placeholder="Full Name *" value={buyerName}
                            onChange={e => { setBuyerName(e.target.value); setSignupError(''); }} />
                        </div>
                        <div className="input-group">
                          <span className="input-icon">📍</span>
                          <input type="text"
                            className={`agri-input ${signupError && role === 'buyer' && !buyerLocation.trim() ? 'input-error' : ''}`}
                            placeholder="Location *" value={buyerLocation}
                            onChange={e => { setBuyerLocation(e.target.value); setSignupError(''); }} />
                        </div>
                        <select className="agri-select" value={buyerInterest} onChange={e => setBuyerInterest(e.target.value)}>
                          <option value="">Select Primary Interest</option>
                          <option>🥦 Vegetables</option>
                          <option>🍎 Fruits</option>
                          <option>🌾 Grains</option>
                        </select>
                      </div>

                      {/* SELLER FORM */}
                      <div className="role-form-panel">
                        <div className="input-group">
                          <span className="input-icon">👤</span>
                          <input type="text"
                            className={`agri-input ${signupError && role === 'seller' && !sellerName.trim() ? 'input-error' : ''}`}
                            placeholder="Full Name *" value={sellerName}
                            onChange={e => { setSellerName(e.target.value); setSignupError(''); }} />
                        </div>
                        <div className="input-group">
                          <span className="input-icon">📍</span>
                          <input type="text"
                            className={`agri-input ${signupError && role === 'seller' && !sellerLocation.trim() ? 'input-error' : ''}`}
                            placeholder="Location *" value={sellerLocation}
                            onChange={e => { setSellerLocation(e.target.value); setSignupError(''); }} />
                        </div>

                        {/* Aadhar + PAN side by side */}
                        <div className="id-row">
                          <div className="input-group half">
                            <span className="input-icon small-icon">🪪</span>
                            <input type="text"
                              className={`agri-input ${signupError && role === 'seller' && !sellerAadhar.trim() ? 'input-error' : ''}`}
                              placeholder="Aadhar No. *" value={sellerAadhar}
                              onChange={e => { setSellerAadhar(e.target.value); setSignupError(''); }} />
                          </div>
                          <div className="input-group half">
                            <span className="input-icon small-icon">📋</span>
                            <input type="text"
                              className={`agri-input ${signupError && role === 'seller' && !sellerPan.trim() ? 'input-error' : ''}`}
                              placeholder="PAN No. *" value={sellerPan}
                              onChange={e => { setSellerPan(e.target.value); setSignupError(''); }} />
                          </div>
                        </div>

                        {/* Styled file upload */}
                        <div
                          className={`file-upload-zone ${sellerFileName ? 'file-selected' : ''} ${signupError && role === 'seller' && !sellerFile ? 'file-error' : ''}`}
                          onClick={() => fileInputRef.current.click()}
                        >
                          <input
                            type="file"
                            ref={fileInputRef}
                            style={{ display: 'none' }}
                            accept=".pdf,.jpg,.jpeg,.png"
                            onChange={handleFileChange}
                          />
                          {sellerFileName ? (
                            <div className="file-chosen">
                              <span className="file-check">✅</span>
                              <span className="file-chosen-name">{sellerFileName}</span>
                            </div>
                          ) : (
                            <div className="file-placeholder">
                              <span className="file-upload-icon">📂</span>
                              <span className="file-upload-text">Upload Income Proof</span>
                              <span className="file-upload-hint">PDF, JPG or PNG · click to browse</span>
                            </div>
                          )}
                        </div>
                      </div>

                    </div>
                  </div>

                  {signupError && <p className="error-msg">{signupError}</p>}
                  <button className="btn-agri full-w mt-10" onClick={handleSignup}>Create Profile 🌱</button>
                  <button className="btn-back" onClick={() => navigate('landing', 'right')}>← Cancel</button>
                </div>
              )}

            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

export default Login;
